static <T> Specification<T> not(Specification<T> spec) {

	Assert.notNull(spec, "Specification must not be null");

	return (root, query, builder) -> {

		Predicate predicate = spec.toPredicate(root, query, builder);
		return predicate != null ? builder.not(predicate) : null;
	};
}

@SafeVarargs
static <T> Specification<T> allOf(Specification<T>... specifications) {
	return allOf(Arrays.asList(specifications));
}

static <T> Specification<T> allOf(Iterable<Specification<T>> specifications) {

	return StreamSupport.stream(specifications.spliterator(), false) //
			.reduce(Specification.unrestricted(), Specification::and);
}

@SafeVarargs
static <T> Specification<T> anyOf(Specification<T>... specifications) {
	return anyOf(Arrays.asList(specifications));
}

static <T> Specification<T> anyOf(Iterable<Specification<T>> specifications) {

	return StreamSupport.stream(specifications.spliterator(), false) //
			.reduce(Specification.unrestricted(), Specification::or);
}

@RequestMapping(value = BASE_MAPPING, method = GET)
	public ResponseEntity<RepresentationModel<?>> followPropertyReference(final RootResourceInformation repoRequest,
			@BackendId Serializable id, final @PathVariable String property,
			RepresentationModelAssemblers assemblers) throws Exception {

		var headers = new HttpHeaders();

		Function<ReferencedProperty, RepresentationModel<?>> handler = prop -> prop.mapValue(it -> {

			if (prop.property.isCollectionLike()) {

				return assemblers.toCollectionModel((Iterable<Object>) it, prop.propertyType);

			} else if (prop.property.isMap()) {

				return ((Map<Object, Object>) it).entrySet().stream() //
						.collect(collectingAndThen(
								toMap(Map.Entry::getKey, entry -> assemblers.toModel(entry.getValue())),
								MapModel::new));

			} else {

				var resource = assemblers.toModel(it);
				headers.set(HttpHeaders.CONTENT_LOCATION, resource.getRequiredLink(IanaLinkRelations.SELF).getHref());
				return resource;
			}

		}).orElseThrow(ResourceNotFoundException::new);

		return ControllerUtils.toResponseEntity(HttpStatus.OK, headers, //
				doWithReferencedProperty(repoRequest, id, property, handler, HttpMethod.GET));
	}

@SuppressWarnings("unchecked")
	private static <T> Optional<SingularAttribute<? super T, ?>> findVersionAttribute(IdentifiableType<T> type,
			Metamodel metamodel) {

		try {
			return Optional.ofNullable(type.getVersion(Object.class));
		} catch (IllegalArgumentException o_O) {
			// Needs workarounds as the method is implemented with a strict type check on e.g. Hibernate < 4.3
		}

		Set<SingularAttribute<? super T, ?>> attributes = type.getSingularAttributes();

		for (SingularAttribute<? super T, ?> attribute : attributes) {
			if (attribute.isVersion()) {
				return Optional.of(attribute);
			}
		}

		Class<?> superType = type.getJavaType().getSuperclass();

		if (!JpaMetamodel.of(metamodel).isJpaManaged(superType)) {
			return Optional.empty();
		}

		ManagedType<?> managedSuperType = metamodel.managedType(superType);

		if (!(managedSuperType instanceof IdentifiableType)) {
			return Optional.empty();
		}

		return findVersionAttribute((IdentifiableType<T>) managedSuperType, metamodel);
	}

@Override
		public String toString() {
			boolean hasNames = !this.names.isEmpty();
			boolean hasTypes = !this.types.isEmpty();
			boolean hasIgnoredTypes = !this.ignoredTypes.isEmpty();
			StringBuilder string = new StringBuilder();
			string.append("(");
			if (hasNames) {
				string.append("names: ");
				string.append(StringUtils.collectionToCommaDelimitedString(this.names));
				string.append(hasTypes ? " " : "; ");
			}
			if (hasTypes) {
				string.append("types: ");
				string.append(StringUtils.collectionToCommaDelimitedString(this.types));
				string.append(hasIgnoredTypes ? " " : "; ");
			}
			if (hasIgnoredTypes) {
				string.append("ignored: ");
				string.append(StringUtils.collectionToCommaDelimitedString(this.ignoredTypes));
				string.append("; ");
			}
			if (this.strategy != null) {
				string.append("SearchStrategy: ");
				string.append(this.strategy.toString().toLowerCase(Locale.ENGLISH));
			}
			string.append(")");
			return string.toString();
		}

private void upsert(Chunk<? extends T> chunk) {
	BulkOperations bulkOperations = initBulkOperations(chunk.getItems().get(0));
	@SuppressWarnings("DataFlowIssue")
	MongoConverter mongoConverter = this.template.getConverter();
	FindAndReplaceOptions upsert = new FindAndReplaceOptions().upsert();
	for (Object item : chunk) {
		Document document = new Document();
		mongoConverter.write(item, document);

		Query query = new Query();
		List<Criteria> criteriaList = primaryKeys.stream()
			.filter(document::containsKey)
			.map(key -> Criteria.where(key).is(document.get(key)))
			.collect(toList());

		if (criteriaList.isEmpty()) {
			Object objectId = document.get(ID_KEY) != null ? document.get(ID_KEY) : new ObjectId();
			query.addCriteria(Criteria.where(ID_KEY).is(objectId));
		}
		else {
			criteriaList.forEach(query::addCriteria);
		}

		bulkOperations.replaceOne(query, document, upsert);
	}
	bulkOperations.execute();
}

@SuppressWarnings("DataFlowIssue")
private BulkOperations initBulkOperations(Object item) {
	return StringUtils.hasText(this.collection) //
			? this.template.bulkOps(BulkMode.ORDERED, this.collection)
			: this.template.bulkOps(BulkMode.ORDERED, ClassUtils.getUserClass(item));
}

@Override
	public ConditionOutcome getMatchOutcome(ConditionContext context, AnnotatedTypeMetadata metadata) {
		ConditionOutcome matchOutcome = ConditionOutcome.match();
		MergedAnnotations annotations = metadata.getAnnotations();
		if (annotations.isPresent(ConditionalOnBean.class)) {
			Spec<ConditionalOnBean> spec = new Spec<>(context, metadata, annotations, ConditionalOnBean.class);
			matchOutcome = evaluateConditionalOnBean(spec, matchOutcome.getConditionMessage());
			if (!matchOutcome.isMatch()) {
				return matchOutcome;
			}
		}
		if (metadata.isAnnotated(ConditionalOnSingleCandidate.class.getName())) {
			Spec<ConditionalOnSingleCandidate> spec = new SingleCandidateSpec(context, metadata,
					metadata.getAnnotations());
			matchOutcome = evaluateConditionalOnSingleCandidate(spec, matchOutcome.getConditionMessage());
			if (!matchOutcome.isMatch()) {
				return matchOutcome;
			}
		}
		if (metadata.isAnnotated(ConditionalOnMissingBean.class.getName())) {
			Spec<ConditionalOnMissingBean> spec = new Spec<>(context, metadata, annotations,
					ConditionalOnMissingBean.class);
			matchOutcome = evaluateConditionalOnMissingBean(spec, matchOutcome.getConditionMessage());
			if (!matchOutcome.isMatch()) {
				return matchOutcome;
			}
		}
		return matchOutcome;
	}

protected ParameterizedTypeReference() {
	Class<?> parameterizedTypeReferenceSubclass = findParameterizedTypeReferenceSubclass(getClass());
	Type type = parameterizedTypeReferenceSubclass.getGenericSuperclass();
	Assert.isInstanceOf(ParameterizedType.class, type, "Type must be a parameterized type");
	ParameterizedType parameterizedType = (ParameterizedType) type;
	Type[] actualTypeArguments = parameterizedType.getActualTypeArguments();
	Assert.isTrue(actualTypeArguments.length == 1, "Number of type arguments must be 1");
	this.type = actualTypeArguments[0];
}

