private static @Nullable Object adaptValue(
		@Nullable Object annotatedElement, @Nullable Object value, boolean classValuesAsString) {

	if (classValuesAsString) {
		if (value instanceof Class<?> clazz) {
			return clazz.getName();
		}
		if (value instanceof Class<?>[] classes) {
			String[] names = new String[classes.length];
			for (int i = 0; i < classes.length; i++) {
				names[i] = classes[i].getName();
			}
			return names;
		}
	}
	if (value instanceof Annotation annotation) {
		return MergedAnnotation.from(annotatedElement, annotation).synthesize();
	}
	if (value instanceof Annotation[] annotations) {
		Annotation[] synthesized = (Annotation[]) Array.newInstance(
				annotations.getClass().componentType(), annotations.length);
		for (int i = 0; i < annotations.length; i++) {
			synthesized[i] = MergedAnnotation.from(annotatedElement, annotations[i]).synthesize();
		}
		return synthesized;
	}
	return value;
}

@SuppressWarnings("unchecked")
	private <A extends Annotation> @Nullable MergedAnnotation<A> find(Object requiredType,
			@Nullable Predicate<? super MergedAnnotation<A>> predicate,
			@Nullable MergedAnnotationSelector<A> selector) {

		if (selector == null) {
			selector = MergedAnnotationSelectors.nearest();
		}

		MergedAnnotation<A> result = null;
		for (int i = 0; i < this.annotations.length; i++) {
			MergedAnnotation<?> root = this.annotations[i];
			if (root != null) {
				AnnotationTypeMappings mappings = this.mappings[i];
				for (int mappingIndex = 0; mappingIndex < mappings.size(); mappingIndex++) {
					AnnotationTypeMapping mapping = mappings.get(mappingIndex);
					if (!isMappingForType(mapping, requiredType)) {
						continue;
					}
					MergedAnnotation<A> candidate = (mappingIndex == 0 ? (MergedAnnotation<A>) root :
							TypeMappedAnnotation.createIfPossible(mapping, root, IntrospectionFailureLogger.INFO));
					if (candidate != null && (predicate == null || predicate.test(candidate))) {
						if (selector.isBestCandidate(candidate)) {
							return candidate;
						}
						result = (result != null ? selector.select(result, candidate) : candidate);
					}
				}
			}
		}
		return result;
	}

@Override
	public <T extends Map<String, Object>> T asMap(Function<MergedAnnotation<?>, T> factory, Adapt... adaptations) {
		T map = factory.apply(this);
		Assert.state(map != null, "Factory used to create MergedAnnotation Map must not return null");
		AttributeMethods attributes = this.mapping.getAttributes();
		for (int i = 0; i < attributes.size(); i++) {
			Method attribute = attributes.get(i);
			if (isFiltered(attribute.getName())) {
				continue;
			}
			Object value;
			try {
				value = getValue(i, getTypeForMapOptions(attribute, adaptations));
			}
			catch (Throwable ex) {
				// If the value for the current annotation attribute cannot be resolved
				// (for example, a class attribute referencing a type that is absent from
				// the classpath), store the exception as the value and skip the "adapt"
				// step. This allows us to track the exception internally and only throw it
				// if the user actually requests the value via the AnnotationAttributes API.
				map.put(attribute.getName(), ex);
				continue;
			}
			if (value != null) {
				map.put(attribute.getName(),
						adaptValueForMapOptions(attribute, value, map.getClass(), factory, adaptations));
			}
		}
		return map;
	}

@Override
		public @Nullable Boolean doWithAnnotations(Object requiredType, int aggregateIndex,
				@Nullable Object source, @Nullable Annotation[] annotations) {

			for (Annotation annotation : annotations) {
				if (annotation != null) {
					Class<? extends Annotation> type = annotation.annotationType();
					if (type != null && !this.annotationFilter.matches(type)) {
						if (type == requiredType || type.getName().equals(requiredType)) {
							return Boolean.TRUE;
						}
						Annotation[] repeatedAnnotations =
								this.repeatableContainers.findRepeatedAnnotations(annotation);
						if (repeatedAnnotations != null) {
							Boolean result = doWithAnnotations(
									requiredType, aggregateIndex, source, repeatedAnnotations);
							if (result != null) {
								return result;
							}
						}
						if (!this.directOnly) {
							AnnotationTypeMappings mappings = AnnotationTypeMappings.forAnnotationType(type);
							for (int i = 0; i < mappings.size(); i++) {
								AnnotationTypeMapping mapping = mappings.get(i);
								if (isMappingForType(mapping, this.annotationFilter, requiredType)) {
									return Boolean.TRUE;
								}
							}
						}
					}
				}
			}
			return null;
		}

private boolean tryAdvance(Aggregate aggregate, Consumer<? super MergedAnnotation<A>> action) {
	if (this.mappingCursors == null) {
		this.mappingCursors = new int[aggregate.size()];
	}
	int lowestDistance = Integer.MAX_VALUE;
	int annotationResult = -1;
	for (int annotationIndex = 0; annotationIndex < aggregate.size(); annotationIndex++) {
		AnnotationTypeMapping mapping = getNextSuitableMapping(aggregate, annotationIndex);
		if (mapping != null && mapping.getDistance() < lowestDistance) {
			annotationResult = annotationIndex;
			lowestDistance = mapping.getDistance();
		}
		if (lowestDistance == 0) {
			break;
		}
	}
	if (annotationResult != -1) {
		MergedAnnotation<A> mergedAnnotation = aggregate.createMergedAnnotationIfPossible(
				annotationResult, this.mappingCursors[annotationResult],
				this.requiredType != null ? IntrospectionFailureLogger.INFO : IntrospectionFailureLogger.DEBUG);
		this.mappingCursors[annotationResult]++;
		if (mergedAnnotation == null) {
			return tryAdvance(aggregate, action);
		}
		action.accept(mergedAnnotation);
		return true;
	}
	return false;
}

@Override
		public Annotation[] getParameterAnnotations() {
			Annotation[] anns = this.combinedAnnotations;
			if (anns == null) {
				anns = super.getParameterAnnotations();
				int index = getParameterIndex();
				if (index >= 0) {
					for (Annotation[][] ifcAnns : getInheritedParameterAnnotations()) {
						if (index < ifcAnns.length) {
							Annotation[] paramAnns = ifcAnns[index];
							if (paramAnns.length > 0) {
								List<Annotation> merged = new ArrayList<>(anns.length + paramAnns.length);
								merged.addAll(Arrays.asList(anns));
								for (Annotation paramAnn : paramAnns) {
									boolean existingType = false;
									for (Annotation ann : anns) {
										if (ann.annotationType() == paramAnn.annotationType()) {
											existingType = true;
											break;
										}
									}
									if (!existingType) {
										merged.add(adaptAnnotation(paramAnn));
									}
								}
								anns = merged.toArray(new Annotation[0]);
							}
						}
					}
				}
				this.combinedAnnotations = anns;
			}
			return anns;
		}

@SuppressWarnings("NullAway") // Dataflow analysis limitation
	static @Nullable Annotation[] getDeclaredAnnotations(AnnotatedElement source, boolean defensive) {
		boolean cached = false;
		@Nullable Annotation[] annotations = declaredAnnotationCache.get(source);
		if (annotations != null) {
			cached = true;
		}
		else {
			annotations = source.getDeclaredAnnotations();
			if (annotations.length != 0) {
				boolean allIgnored = true;
				for (int i = 0; i < annotations.length; i++) {
					Annotation annotation = annotations[i];
					//noinspection DataFlowIssue
					if (isIgnorable(annotation.annotationType()) ||
							!AttributeMethods.forAnnotationType(annotation.annotationType()).canLoad(annotation, source)) {
						annotations[i] = null;
					}
					else {
						allIgnored = false;
					}
				}
				annotations = (allIgnored ? NO_ANNOTATIONS : annotations);
				if (source instanceof Class || source instanceof Member) {
					//noinspection NullableProblems
					declaredAnnotationCache.put(source, annotations);
					cached = true;
				}
			}
		}
		if (!defensive || annotations.length == 0 || !cached) {
			return annotations;
		}
		return annotations.clone();
	}

private static Map<String, DefaultValueHolder> computeDefaultValues(
		Class<? extends Annotation> annotationType) {

	AttributeMethods methods = AttributeMethods.forAnnotationType(annotationType);
	if (!methods.hasDefaultValueMethod()) {
		return Collections.emptyMap();
	}
	Map<String, DefaultValueHolder> result = CollectionUtils.newLinkedHashMap(methods.size());
	if (!methods.hasNestedAnnotation()) {
		// Use simpler method if there are no nested annotations
		for (int i = 0; i < methods.size(); i++) {
			Method method = methods.get(i);
			Object defaultValue = method.getDefaultValue();
			if (defaultValue != null) {
				result.put(method.getName(), new DefaultValueHolder(defaultValue));
			}
		}
	}
	else {
		// If we have nested annotations, we need them as nested maps
		AnnotationAttributes attributes = MergedAnnotation.of(annotationType)
				.asMap(annotation ->
						new AnnotationAttributes(annotation.getType(), true), Adapt.ANNOTATION_TO_MAP);
		for (Map.Entry<String, Object> element : attributes.entrySet()) {
			result.put(element.getKey(), new DefaultValueHolder(element.getValue()));
		}
	}
	return result;
}

private static Method resolveBridgeMethod(Method bridgeMethod, Class<?> targetClass) {
	Class<?> userClass = targetClass;
	if (!bridgeMethod.isBridge()) {
		userClass = ClassUtils.getUserClass(targetClass);
		if (userClass == targetClass) {
			return bridgeMethod;
		}
	}

	boolean localBridge = (targetClass == bridgeMethod.getDeclaringClass());
	Object cacheKey = (localBridge ? bridgeMethod : new MethodClassKey(bridgeMethod, targetClass));
	Method bridgedMethod = cache.get(cacheKey);
	if (bridgedMethod == null) {
		// Gather all methods with matching name and parameter size.
		List<Method> candidateMethods = new ArrayList<>();
		ReflectionUtils.doWithMethods(userClass, candidateMethods::add,
				candidateMethod -> isBridgedCandidateFor(candidateMethod, bridgeMethod));
		if (!candidateMethods.isEmpty()) {
			bridgedMethod = (candidateMethods.size() == 1 ? candidateMethods.get(0) :
					searchCandidates(candidateMethods, bridgeMethod, targetClass));
		}
		if (bridgedMethod == null) {
			// A bridge method was passed in but we couldn't find the bridged method.
			// Let's proceed with the passed-in method and hope for the best...
			bridgedMethod = bridgeMethod;
		}
		cache.put(cacheKey, bridgedMethod);
	}
	return bridgedMethod;
}

public boolean fieldRequired(Field field, io.swagger.v3.oas.annotations.media.Schema schema, Parameter parameter) {
	Boolean swagger = swaggerRequired(schema, parameter);
	if (swagger != null) return swagger;

	// Optional-like wrapper → not required
	if (OPTIONAL_TYPES.stream().anyMatch(c -> c.isAssignableFrom(field.getType()))) return false;

	// @Nullable/@NotNull
	if (hasNullableAnnotation(field) || hasNullableOnGetter(field) || hasNullableOnCtorParam(field)) {
		return false;
	}
	if (hasNotNullAnnotation(field) || hasNotNullOnGetter(field) || hasNotNullOnCtorParam(field)) {
		return true;
	}

	// Kotlin logic
	if (kotlinUtilsOptional.isPresent()  && isKotlinDeclaringClass(field)) {
		if (fieldNullable(field)) return false;
		Boolean hasDefault = kotlinConstructorParamIsOptional(field);
		if (Boolean.TRUE.equals(hasDefault)) return false;
		return true;
	}

	// Jackson @JsonProperty(required = true)
	JsonProperty jp = getJsonProperty(field);
	if (jp != null && jp.required()) return true;

	return false;
}

@Override
	public void start() {
		this.lock.lock();
		try {
			if (this.queueToConsumers.isEmpty()) {
				ReceiverOptions receiverOptions =
						new ReceiverOptions()
								// Since 'AmqpConsumer' implements pause/resume logic,
								// the auto-replenishment for the credit window is disabled.
								.creditWindow(0)
								.autoAccept(this.autoAccept);

				for (String queue : this.queues) {
					for (int i = 0; i < this.consumersPerQueue; i++) {
						try {
							Future<Receiver> openFuture =
									this.connectionFactory.getConnection()
											.openReceiver(queue, receiverOptions)
											.openFuture();
							ClientReceiver receiver =
									(ClientReceiver) ProtonUtils.toSupplier(openFuture, receiverOptions.openTimeout())
											.get()
											.addCredit(this.initialCredits);
							AmqpConsumer consumer = new AmqpConsumer(receiver);
							this.queueToConsumers.add(queue, consumer);
							this.taskExecutor.execute(consumer);
						}
						catch (ClientException ex) {
							throw ProtonUtils.toAmqpException(ex);
						}
					}
				}
			}
		}
		finally {
			this.lock.unlock();
		}
	}

@SuppressWarnings("unchecked")
	private <T> T getRequiredAttribute(String attributeName, Class<T> expectedType) {
		Assert.hasText(attributeName, "'attributeName' must not be null or empty");
		Object value = get(attributeName);
		if (value == null) {
			throw new IllegalArgumentException(String.format(
					"Attribute '%s' not found in attributes for annotation [%s]",
					attributeName, this.displayName));
		}
		if (value instanceof Throwable throwable) {
			throw new IllegalArgumentException(String.format(
					"Attribute '%s' for annotation [%s] was not resolvable due to exception [%s]",
					attributeName, this.displayName, value), throwable);
		}
		if (!expectedType.isInstance(value) && expectedType.isArray() &&
				expectedType.componentType().isInstance(value)) {
			Object array = Array.newInstance(expectedType.componentType(), 1);
			Array.set(array, 0, value);
			value = array;
		}
		if (!expectedType.isInstance(value)) {
			throw new IllegalArgumentException(String.format(
					"Attribute '%s' is of type %s, but %s was expected in attributes for annotation [%s]",
					attributeName, value.getClass().getSimpleName(), expectedType.getSimpleName(),
					this.displayName));
		}
		return (T) value;
	}

private List<String> createCommand(Type type) {
	return switch (type) {
		case DOCKER -> new ArrayList<>(this.dockerCommands.get(type).command());
		case DOCKER_COMPOSE -> {
			List<String> result = new ArrayList<>(this.dockerCommands.get(type).command());
			DockerComposeFile composeFile = this.dockerComposeOptions.composeFile();
			if (composeFile != null) {
				for (File file : composeFile.getFiles()) {
					result.add("--file");
					result.add(file.getPath());
				}
			}
			result.add("--ansi");
			result.add("never");
			Set<String> activeProfiles = this.dockerComposeOptions.activeProfiles();
			if (!CollectionUtils.isEmpty(activeProfiles)) {
				for (String profile : activeProfiles) {
					result.add("--profile");
					result.add(profile);
				}
			}
			List<String> arguments = this.dockerComposeOptions.arguments();
			if (!CollectionUtils.isEmpty(arguments)) {
				result.addAll(arguments);
			}
			yield result;
		}
	};
